module fsm(
    input IN,
    input CLK,
    input RST,
    output MATCH
);

    reg [2:0] state, next_state;
    reg match_reg;

    // State encoding
    localparam IDLE = 3'b000;
    localparam S1   = 3'b001;
    localparam S10  = 3'b010;
    localparam S100 = 3'b011;
    localparam S1001 = 3'b100;

    // Combinational logic for next state and output
    always @(*) begin
        match_reg = 1'b0;
        next_state = state;

        case (state)
            IDLE: begin
                if (IN == 1'b1) begin
                    next_state = S1;
                end else begin
                    next_state = IDLE;
                end
            end

            S1: begin
                if (IN == 1'b0) begin
                    next_state = S10;
                end else begin
                    next_state = S1;
                end
            end

            S10: begin
                if (IN == 1'b0) begin
                    next_state = S100;
                end else begin
                    next_state = S1;
                end
            end

            S100: begin
                if (IN == 1'b1) begin
                    next_state = S1001;
                end else begin
                    next_state = IDLE;
                end
            end

            S1001: begin
                if (IN == 1'b1) begin
                    match_reg = 1'b1;
                    next_state = S1;
                end else begin
                    next_state = S10;
                end
            end

            default: begin
