module LIFObuffer(
    input [3:0] dataIn,
    input RW,
    input EN,
    input Rst,
    input Clk,
    output EMPTY,
    output FULL,
    output [3:0] dataOut
);

    reg [3:0] stack_mem [0:3];  // 4-entry stack memory, each 4-bit wide
    reg [2:0] SP;               // Stack pointer (0-3 for valid entries, 4 for empty)
    reg [3:0] dataOut_reg;      // Register to hold output data

    // Assign outputs
    assign EMPTY = (SP == 3'b100) ? 1'b1 : 1'b0;  // Empty when SP = 4
    assign FULL = (SP == 3'b000) ? 1'b1 : 1'b0;   // Full when SP = 0
    assign dataOut = dataOut_reg;

    always @(posedge Clk) begin
        if (EN) begin
            if (Rst) begin
                // Reset: clear stack and initialize SP
                SP <= 3'b100;           // SP = 4 (empty)
                stack_mem[0] <= 4'b0000;
                stack_mem[1] <= 4'b0000;
                stack_mem[2] <= 4'b0000;
                stack_mem[3] <= 4'b0000;
                dataOut_reg <= 4'b0000;
            end
            else begin
                // Normal operation
                if (~RW) begin
                    // Write operation (RW = 0)
                    if (~FULL) begin
                        // Push data onto stack
                        stack_mem[SP] <= dataIn;
                        SP <= SP - 1'b1;
                    end
                end
                else begin
                    // Read operation (RW = 1)
                    if (~EMPTY) begin
                        // Pop data from stack
                        dataOut_reg <= stack_mem[SP];
                        stack_mem[SP] <= 4'b0000;
                        SP <= SP + 1'b1;
                    end
                end
            end
        end
    end

endmodule

